import requests
from xml.etree import ElementTree as ET

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info
    
    def build_saml_request(self):
        # Construct the SAML XML
        saml_xml = """<?xml version="1.0" encoding="UTF-8"?>
            <samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol" 
                                xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion" 
                                ID="_1234567890abcdefg" Version="2.0" 
                                IssueInstant="2022-01-01T00:00:00Z" Destination="{}">
              <saml:Issuer>https://example.com/saml</saml:Issuer>
              <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:2.0:nameid-format:persistent"/>
              <samlp:RequestedAuthnContext Comparison="minimum">
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
              </samlp:RequestedAuthnContext>
            </samlp:AuthnRequest>""".format(self.destination_url)
        
        # Encode the SAML request and POST it to the Identity Provider
        encoded_request = saml_xml.encode("utf-8")
        response = requests.post(self.destination_url, data=encoded_request)
        
        # Check for errors in the response
        if response.status_code != 200:
            raise Exception("Error sending SAML request to Identity Provider")
            
        return response.text